@dataclass
class Vector3:
    x: float = 0.0
    y: float = 0.0
    z: float = 0.0

    def distance_to(self, other: 'Vector3') -> float:
        return math.sqrt(
            (self.x - other.x) ** 2 +
            (self.y - other.y) ** 2 +
            (self.z - other.z) ** 2
        )

    def to_dict(self):
        return {"x": self.x, "y": self.y, "z": self.z}

    @staticmethod
    def from_dict(d):
        return Vector3(d.get("x", 0), d.get("y", 0), d.get("z", 0))


@dataclass
class Obstacle:
    position: Vector3
    width: float
    height: float
    depth: float
    obstacle_id: str = field(default_factory=lambda: str(uuid.uuid4())[:8])

    def to_dict(self):
        return {
            "obstacle_id": self.obstacle_id,
            "position": self.position.to_dict(),
            "width": self.width,
            "height": self.height,
            "depth": self.depth,
        }

    def contains_point_2d(self, px: float, pz: float) -> bool:
        half_w = self.width / 2
        half_d = self.depth / 2
        return (self.position.x - half_w <= px <= self.position.x + half_w and
                self.position.z - half_d <= pz <= self.position.z + half_d)

    def intersects_segment_2d(self, x1: float, z1: float, x2: float, z2: float) -> bool:
        half_w = self.width / 2
        half_d = self.depth / 2
        min_x = self.position.x - half_w
        max_x = self.position.x + half_w
        min_z = self.position.z - half_d
        max_z = self.position.z + half_d

        dx = x2 - x1
        dz = z2 - z1

        t_min = 0.0
        t_max = 1.0

        for p, d, box_min, box_max in [
            (x1, dx, min_x, max_x),
            (z1, dz, min_z, max_z)
        ]:
            if abs(d) < 1e-10:
                if p < box_min or p > box_max:
                    return False
            else:
                t1 = (box_min - p) / d
                t2 = (box_max - p) / d
                if t1 > t2:
                    t1, t2 = t2, t1
                t_min = max(t_min, t1)
                t_max = min(t_max, t2)
                if t_min > t_max:
                    return False

        return True


