class GameMap:
    def __init__(self, width: float = 2000.0, height: float = 2000.0):
        self.width = width
        self.height = height
        self.obstacles: List[Obstacle] = []
        self.loot_items: Dict[str, LootItem] = {}
        self._generate_map()

    def _generate_map(self):
        random.seed(42)

        # Generate buildings/obstacles
        num_obstacles = 150
        for i in range(num_obstacles):
            pos = Vector3(
                random.uniform(-self.width / 2 + 50, self.width / 2 - 50),
                0,
                random.uniform(-self.height / 2 + 50, self.height / 2 - 50),
            )
            w = random.uniform(5, 30)
            h = random.uniform(3, 20)
            d = random.uniform(5, 30)
            self.obstacles.append(Obstacle(pos, w, h, d))

        # Generate loot
        loot_types = [
            ("weapon", "assault_rifle"),
            ("weapon", "shotgun"),
            ("weapon", "sniper"),
            ("weapon", "smg"),
            ("weapon", "dmr"),
            ("weapon", "pistol"),
            ("health", "medkit"),
            ("health", "bandage"),
            ("armor", "light_armor"),
            ("armor", "heavy_armor"),
            ("ammo", "ammo_box"),
        ]

        for i in range(400):
            item_type, item_name = random.choice(loot_types)
            pos = Vector3(
                random.uniform(-self.width / 2 + 10, self.width / 2 - 10),
                0,
                random.uniform(-self.height / 2 + 10, self.height / 2 - 10),
            )
            item_id = f"loot_{i}_{str(uuid.uuid4())[:6]}"
            props = {}
            if item_type == "weapon":
                props = WEAPON_TEMPLATES[item_name].to_dict() if item_name in WEAPON_TEMPLATES else {}
            elif item_type == "health":
                props = {"heal_amount": 100 if item_name == "medkit" else 25}
            elif item_type == "armor":
                props = {"armor_amount": 100 if item_name == "heavy_armor" else 50}
            elif item_type == "ammo":
                props = {"ammo_count": 60}

            self.loot_items[item_id] = LootItem(item_id, item_type, item_name, pos, properties=props)

    def check_line_of_sight(self, from_pos: Vector3, to_pos: Vector3) -> bool:
        for obs in self.obstacles:
            if obs.intersects_segment_2d(from_pos.x, from_pos.z, to_pos.x, to_pos.z):
                if (min(from_pos.y, to_pos.y) < obs.position.y + obs.height):
                    return False
        return True

    def to_dict(self):
        return {
            "width": self.width,
            "height": self.height,
            "obstacles": [o.to_dict() for o in self.obstacles],
        }


class BattleRoyaleGame:
    def __init__(self):
        self.game_id = str(uuid.uuid4())[:8]
        self.players: Dict[str, Player] = {}
        self.connections: Dict[str, websockets.WebSocketServerProtocol] = {}
        self.game_phase = GamePhase.WAITING
        self.game_map = GameMap()
        self.projectiles: Dict[str, Projectile] = {}
        self.kill_feed: List[KillFeedEntry] = []
        self.storm: Optional[StormCircle] = None
        self.tick_rate = 20  # server ticks per second
        self.broadcast_rate = 20  # full state broadcasts per second
        self.max_players = 100
        self.min_players_to_start = 2
        self.game_start_time: Optional[float] = None
        self.countdown_duration = 10.0
        self.players_alive_count = 0
        self.winner: Optional[str] = None
        self.storm_phases = [
            {"delay": 120, "shrink_time": 60, "target_radius": 700, "damage": 1},
            {"delay": 90, "shrink_time": 50, "target_radius": 450, "damage": 2},
            {"delay": 75, "shrink_time": 40, "target_radius": 250, "damage": 5},
            {"delay": 60, "shrink_time": 30, "target_radius": 120, "damage": 8},
            {"delay": 45, "shrink_time": 20, "target_radius": 50, "damage": 10},
            {"delay": 30, "shrink_time": 15, "target_radius": 10, "damage": 15},
            {"delay": 15, "shrink_time": 10, "target_radius": 0, "damage": 20},
        ]
        self.current_storm_phase = 0
        self.storm_phase_start_time: Optional[float] = None
        self.storm_shrinking = False
        self._state_seq = 0
        self._running = False

    def _init_storm(self):
        center = Vector3(
            random.uniform(-200, 200),
            0,
            random.uniform(-200, 200),
        )
        self.storm = StormCircle(
            center=center,
            current_radius=1000,
            target_radius=self.storm_phases[0]["target_radius"],
            shrink_rate=0,
            damage_per_second=self.storm_phases[0]["damage"],
            phase=0,
        )
        self.storm_phase_start_time = time.time()
        self.storm_shrinking = False
        self.current_storm_phase = 0

    def _spawn_position(self) -> Vector3:
        angle = random.uniform(0, 2 * math.pi)
        radius = random.uniform(500, 900)
        return Vector3(
            math.cos(angle) * radius,
            100,  # drop from sky
            math.sin(angle) * radius,
        )

    async def add_player(self, ws, username: str) -> Optional[Player]:
        if len(self.players) >= self.max_players:
            await ws.send(json.dumps({"type": "error", "message": "Server full"}))
            return None

        if self.game_phase not in (GamePhase.WAITING, GamePhase.COUNTDOWN):
            await ws.send(json.dumps({"type": "error", "message": "Game already in progress"}))
            return None

        player_id = str(uuid.uuid4())[:12]
        spawn = self._spawn_position()

        player = Player(
            player_id=player_id,
            username=username,
            position=spawn,
            weapon=WeaponInfo(**{
                "name": "Pistol", "damage": 18, "fire_rate": 4.0,
                "range": 50, "ammo": 12, "max_ammo": 12,
                "reload_time": 1.5, "projectile_speed": 300,
            }),
            last_update_time=time.time(),
        )

        self.players[player_id] = player
        self.connections[player_id] = ws

        # Send initial data to the new player
        await ws.send(json.dumps({
            "type": "connected",
            "player_id": player_id,
            "game_id": self.game_id,
            "map_data": self.game_map.to_dict(),
            "loot_items": {k: v.to_dict() for k, v in self.game_map.loot_items.items() if not v.picked_up},
            "game_phase": self.game_phase.value,
            "tick_rate": self.tick_rate,
        }))

        # Broadcast player joined
        await self.broadcast({
            "type": "player_joined",
            "player": player.to_dict(),
            "player_count": len(self.players),
        })

        logger.info(f"Player {username} ({player_id}) joined. Total: {len(self.players)}")

        # Check if we should start countdown
        if (self.game_phase == GamePhase.WAITING and
                len(self.players) >= self.min_players_to_start):
            await self._start_countdown()

        return player

    async def remove_player(self, player_id: str):
        if player_id in self.players:
            player = self.players[player_id]
            player.connected = False
            player.state = PlayerState.DEAD

            if player_id in self.connections:
                del self.connections[player_id]

            await self.broadcast({
                "type": "player_left",
                "player_id": player_id,
                "username": player.username,
            })

            logger.info(f"Player {player.username} ({player_id}) left")
            self._update_alive_count()

    async def _start_countdown(self):
        self.game_phase = GamePhase.COUNTDOWN
        self.game_start_time = time.time() + self.countdown_duration

        await self.broadcast({
            "type": "phase_change",
            "phase": self.game_phase.value,
            "countdown": self.countdown_duration,
            "start_time": self.game_start_time,
        })

    async def _start_game(self):
        self.game_phase = GamePhase.PLAYING
        self.players_alive_count = sum(
            1 for p in self.players.values() if p.connected
        )
        self._init_storm()

        # Assign proper spawn positions
        for player in self.players.values():
            if player.connected:
                player.state = PlayerState.ALIVE
                player.position = self._spawn_position()

        await self.broadcast({
            "type": "phase_change",
            "phase": self.game_phase.value,
            "storm": self.storm.to_dict() if self.storm else None,
            "players_alive": self.players_alive_count,
        })

        logger.info(f"Game started with {self.players_alive_count} players")

    def _update_alive_count(self):
        self.players_alive_count = sum(
            1 for p in self.players.values()
            if p.state == PlayerState.ALIVE and p.connected
        )

    async def handle_player_input(self, player_id: str, data: dict):
        if player_id not in self.players:
            return

        player = self.players[player_id]
        msg_type = data.get("type")

        if msg_type == "move":
            await self._handle_move(player, data)
        elif msg_type == "shoot":
            await self._handle_shoot(player, data)
        elif msg_type == "reload":
            await self._handle_reload(player)
        elif msg_type == "pickup":
            await self._handle_pickup(player, data)
        elif msg_type == "use_item":
            await self._handle_use_item(player, data)
        elif msg_type == "drop_item":
            await self._handle_drop_item(player, data)
        elif msg_type == "crouch":
            player.is_crouching = data.get("crouching", False)
        elif msg_type == "sprint":
            player.is_sprinting = data.get("sprinting", False)
        elif msg_type == "ping":
            ws = self.connections.get(player_id)
            if ws:
                await ws.send(json.dumps({
                    "type": "pong",
                    "client_time": data.get("client_time", 0),
                    "server_time": time.time(),
                }))

    async def _handle_move(self, player: Player, data: dict):
        if player.state != PlayerState.ALIVE:
            return

        now = time.time()
        dt = now - player.last_update_time
        player.last_update_time = now

        new_pos = Vector3.from_dict(data.get("position", {}))
        new_vel = Vector3.from_dict(data.get("velocity", {}))
        new_rot = data.get("rotation", player.rotation)
        new_pitch = data.get("pitch", player.pitch)

        # Basic server-side speed validation
        max_speed = 15.0  # units per second
        if player.is_sprinting:
            max_speed = 22.0
        if player.is_crouching:
            max_speed = 7.0

        dist = player.position.distance_to(new_pos)
        max_allowed = max_speed * max(dt, 0.1) * 1.5  # small tolerance

        if dist <= max_allowed or dt > 1.0:
            # Check obstacle collision (simple)
            blocked = False
            for obs in self.game_map.obstacles:
                if obs.contains_point_2d(new_pos.x, new_pos.z):
                    if new_pos.y < obs.position.y + obs.height:
                        blocked = True
                        break

            if not blocked:
                player.position = new_pos
                player.velocity = new_vel
            else:
                # Reject move - send correction
                ws = self.connections.get(player.player_id)
                if ws:
                    await ws.send(json.dumps({
                        "type": "position_correction",
                        "position": player.position.to_dict(),
                    }))
        else:
            # Possible speed hack - send correction
            logger.warning(
                f"Speed violation for {player.username}: dist={dist:.2f}, max={max_allowed:.2f}, dt={dt:.3f}"
            )
            ws = self.connections.get(player.player_id)
            if ws:
                await ws.send(json.dumps({
                    "type": "position_correction",
                    "position": player.position.to_dict(),
                    "reason": "speed_violation",
                }))

        player.rotation = new_rot
        player.pitch = new_pitch

    async def _handle_shoot(self, player: Player, data: dict):
        if player.state != PlayerState.ALIVE:
            return
        if not player.weapon:
            return

        now = time.time()
        fire_interval = 1.0 / player.weapon.fire_rate
        if now - player.last_shot_time < fire_interval * 0.9:
            return

        if player.weapon.ammo <= 0:
            ws = self.connections.get(player.player_id)
            if ws:
                await ws.send(json.dumps({"type": "no_ammo"}))
            return

        player.weapon.ammo -= 1
        player.last_shot_time = now

        # Calculate shot direction from rotation and pitch
        target_dir = data.get("direction", {})
        dir_x = target_dir.get("x", math.cos(math.radians(player.rotation)))
        dir_y = target_dir.get("y", math.sin(math.radians(player.pitch)))
        dir_z = target_dir.get("z", math.sin(math.radians(player.rotation)))

        # Normalize
        mag = math.sqrt(dir_x ** 2 + dir_y ** 2 + dir_z ** 2)
        if mag > 0:
            dir_x /= mag
            dir_y /= mag
            dir_z /= mag

        speed = player.weapon.projectile_speed

        proj_id = str(uuid.uuid4())[:10]
        projectile = Projectile(
            projectile_id=proj_id,
            owner_id=player.player_id,
            position=Vector3(player.position.x, player.position.y + 1.5, player.position.z),
            velocity=Vector3(dir_x * speed, dir_y * speed, dir_z * speed),
            damage=player.weapon.damage,
            timestamp=now,
        )
        self.projectiles[proj_id] = projectile

        # Hitscan check for instant weapons (or do projectile sim)
        hit_result = self._perform_hitscan(player, dir_x, dir_y, dir_z, player.weapon.range)

        if hit_result:
            hit_player, headshot, hit_point = hit_result
            actual_damage = player.weapon.damage
            if headshot:
                actual_damage *= 2.0

            await self._apply_damage(player, hit_player, actual_damage, headshot)

        await self.broadcast({
            "type": "shot_fired",
            "player_id": player.player_id,
            "position": player.position.to_dict(),
            "direction": {"x": dir_x, "y": dir_y, "z": dir_z},
            "weapon": player.weapon.name,
            "hit": hit_result is not None,
            "hit_player_id": hit_result[0].player_id if hit_result else None,
            "headshot": hit_result[1] if hit_result else False,
        })

    def _perform_hitscan(self, shooter: Player, dir_x: float, dir_y: float, dir_z: float,
                         max_range: float) -> Optional[Tuple[Player, bool, Vector3]]:
        best_hit = None
        best_dist = max_range

        for pid, target in self.players.items():
            if pid == shooter.player_id:
                continue
            if target.state != PlayerState.ALIVE:
                continue

            # Ray-sphere intersection for body (simplified)
            body_radius = 0.5
            head_radius = 0.25
            body_center = Vector3(target.position.x, target.position.y + 1.0, target.position.z)
            head_center = Vector3(target.position.x, target.position.y + 1.8, target.position.z)

            origin = Vector3(shooter.position.x, shooter.position.y + 1.5, shooter.position.z)

            # Check head first
            head_hit, head_dist = self._ray_sphere_intersect(
                origin, dir_x, dir_y, dir_z, head_center, head_radius
            )
            if head_hit and head_dist < best_dist:
                # Check line of sight
                hit_point = Vector3(
                    origin.x + dir_x * head_dist,
                    origin.y + dir_y * head_dist,
                    origin.z + dir_z * head_dist,
                )
                if self.game_map.check_line_of_sight(origin, hit_point):
                    best_dist = head_dist
                    best_hit = (target, True, hit_point)
                    continue

            # Check body
            body_hit, body_dist = self._ray_sphere_intersect(
                origin, dir_x, dir_y, dir_z, body_center, body_radius
            )
            if body_hit and body_dist < best_dist:
                hit_point = Vector3(
                    origin.x + dir_x * body_dist,
                    origin.y + dir_y * body_dist,
                    origin.z + dir_z * body_dist,
                )
                if self.game_map.check_line_of_sight(origin, hit_point):
                    best_dist = body_dist
                    best_hit = (target, False, hit_point)

        return best_hit

    @staticmethod
    def _ray_sphere_intersect(origin: Vector3, dir_x: float, dir_y: float, dir_z: float,
                              center: Vector3, radius: float) -> Tuple[bool, float]:
        ox = origin.x - center.x
        oy = origin.y - center.y
        oz = origin.z - center.z

        a = dir_x * dir_x + dir_y * dir_y + dir_z * dir_z
        b = 2.0 * (ox * dir_x + oy * dir_y + oz * dir_z)
        c = ox * ox + oy * oy + oz * oz - radius * radius

        discriminant = b * b - 4 * a * c

        if discriminant < 0:
            return False, float('inf')

        sqrt_disc = math.sqrt(discriminant)
        t1 = (-b - sqrt_disc) / (2 * a)
        t2 = (-b + sqrt_disc) / (2 * a)

        if t1 > 0:
            return True, t1
        elif t2 > 0:
            return True, t2
        return False, float('inf')

    async def _apply_damage(self, attacker: Player, victim: Player, damage: float, headshot: bool):
        if victim.state != PlayerState.ALIVE:
            return

        # Apply damage to armor first
        armor_damage = min(victim.armor, damage * 0.5)
        victim.armor -= armor_damage
        remaining_damage = damage - armor_damage
        victim.health -= remaining_damage
        attacker.damage_dealt += damage

        # Send damage event to victim
        ws = self.connections.get(victim.player_id)
        if ws:
            try:
                await ws.send(json.dumps({
                    "type": "damage_taken",
                    "damage": damage,
                    "health": victim.health,
                    "armor": victim.armor,
                    "attacker_id": attacker.player_id,
                    "headshot": headshot,
                }))
            except:
                pass

        # Send hit confirmation to attacker
        ws = self.connections.get(attacker.player_id)
        if ws:
            try:
                await ws.send(json.dumps({
                    "type": "hit_confirmed",
                    "target_id": victim.player_id,
                    "damage": damage,
                    "headshot": headshot,
                    "target_health": max(0, victim.health),
                }))
            except:
                pass

        if victim.health <= 0:
            victim.health = 0
            victim.state = PlayerState.DEAD
            attacker.kills += 1

            kill_entry = KillFeedEntry(
                killer_id=attacker.player_id,
                killer_name=attacker.username,
                victim_id=victim.player_id,
                victim_name=victim.username,
                weapon=attacker.weapon.name if attacker.weapon else "Unknown",
                timestamp=time.time(),
                headshot=headshot,
            )
            self.kill_feed.append(kill_entry)

            # Keep only last 20 entries
            if len(self.kill_feed) > 20:
                self.kill_feed = self.kill_feed[-20:]

            self._update_alive_count()

            await self.broadcast({
                "type": "player_killed",
                "kill_feed_entry": kill_entry.to_dict(),
                "players_alive": self.players_alive_count,
            })

            # Drop victim's loot
            await self._drop_death_loot(victim)

            # Check win condition
            await self._check_win_condition()

    async def _drop_death_loot(self, player: Player):
        if player.weapon and player.weapon.name != "Pistol":
            item_id = f"death_loot_{str(uuid.uuid4())[:6]}"
            weapon_key = player.weapon.name.lower().replace(" ", "_")
            loot = LootItem(
                item_id=item_id,
                item_type="weapon",
                item_name=weapon_key,
                position=Vector3(player.position.x, player.position.y, player.position.z),
                properties=player.weapon.to_dict(),
            )
            self.game_map.loot_items[item_id] = loot

            await self.broadcast({
                "type": "loot_spawned",
                "item": loot.to_dict(),
            })

    async def _handle_reload(self, player: Player):
        if player.state != PlayerState.ALIVE or not player.weapon:
            return
        if player.weapon.ammo >= player.weapon.max_ammo:
            return

        player.weapon.ammo = player.weapon.max_ammo

        ws = self.connections.get(player.player_id)
        if ws:
            await ws.send(json.dumps({
                "type": "reload_complete",
                "ammo": player.weapon.ammo,
            }))

    async def _handle_pickup(self, player: Player, data: dict):
        if player.state != PlayerState.ALIVE:
            return

        item_id = data.get("item_id")
        if not item_id or item_id not in self.game_map.loot_items:
            return

        item = self.game_map.loot_items[item_id]
        if item.picked_up:
            return

        pickup_range = 3.0
        if player.position.distance_to(item.position) > pickup_range:
            return

        item.picked_up = True

        if item.item_type == "weapon" and item.item_name in WEAPON_TEMPLATES:
            template = WEAPON_TEMPLATES[item.item_name]
            player.weapon = WeaponInfo(
                name=template.name,
                damage=template.damage,
                fire_rate=template.fire_rate,
                range=template.range,
                ammo=template.ammo,
                max_ammo=template.max_ammo,
                reload_time=template.reload_time,
                projectile_speed=template.projectile_speed,
            )
        elif item.item_type == "health":
            heal = item.properties.get("heal_amount", 25)
            player.health = min(100, player.health + heal)
        elif item.item_type == "armor":
            armor = item.properties.get("armor_amount", 50)
            player.armor = min(100, player.armor + armor)
        elif item.item_type == "ammo":
            if player.weapon:
                player.weapon.ammo = player.weapon.max_ammo

        ws = self.connections.get(player.player_id)
        if ws:
            await ws.send(json.dumps({
                "type": "item_picked_up",
                "item_id": item_id,
                "item": item.to_dict(),
                "health": player.health,
                "armor": player.armor,
                "weapon": player.weapon.to_dict() if player.weapon else None,
            }))

        await self.broadcast({
            "type": "loot_removed",
            "item_id": item_id,
        })

    async def _handle_use_item(self, player: Player, data: dict):
        pass  # Extend for consumable items

    async def _handle_drop_item(self, player: Player, data: dict):
        pass  # Extend for item dropping

    async def _check_win_condition(self):
        if self.game_phase not in (GamePhase.PLAYING, GamePhase.FINAL_CIRCLE):
            return

        alive_players = [
            p for p in self.players.values()
            if p.state == PlayerState.ALIVE and p.connected
        ]

        if len(alive_players) <= 1:
            self.game_phase = GamePhase.ENDED
            winner = alive_players[0] if alive_players else None
            self.winner = winner.player_id if winner else None

            await self.broadcast({
                "type": "game_over",
                "winner": winner.to_dict() if winner else None,
                "phase": self.game_phase.value,
                "final_standings": self._get_standings(),
            })

            logger.info(f"Game over! Winner: {winner.username if winner else 'None'}")

    def _get_standings(self) -> List[dict]:
        sorted_players = sorted(
            self.players.values(),
            key=lambda p: (p.state == PlayerState.ALIVE, p.kills, p.damage_dealt),
            reverse=True,
        )
        return [
            {
                "player_id": p.player_id,
                "username": p.username,
                "kills": p.kills,
                "damage_dealt": p.damage_dealt,
                "state": p.state.value,
            }
            for p in sorted_players
        ]

    def _update_storm(self, dt: float):
        if not self.storm or self.game_phase not in (GamePhase.PLAYING, GamePhase.FINAL_CIRCLE):
            return

        now = time.time()
        elapsed = now - self.storm_phase_start_time

        if self.current_storm_phase >= len(self.storm_phases):
            return

        phase_config = self.storm_phases[self.current_storm_phase]

        if not self.storm_shrinking:
            if elapsed >= phase_config["delay"]:
                self.storm_shrinking = True
                self.storm.target_radius = phase_config["target_radius"]
                total_distance = self.storm.current_radius - self.storm.target_radius
                if phase_config["shrink_time"] > 0:
                    self.storm.shrink_rate = total_distance / phase_config["shrink_time"]
                else:
                    self.storm.shrink_rate = total_distance
                self.storm.damage_per_second = phase_config["damage"]
        else:
            if self.storm.current_radius > self.storm.target_radius:
                self.storm.current_radius -= self.storm.shrink_rate * dt
                self.storm.current_radius = max(self.storm.current_radius, self.storm.target_radius)

                # Shift storm center slightly
                shift_rate = 2.0 * dt
                self.storm.center.x += random.uniform(-shift_rate, shift_rate)
                self.storm.center.z += random.uniform(-shift_rate, shift_rate)
            else:
                # Move to next phase
                self.current_storm_phase += 1
                self.storm_shrinking = False
                self.storm_phase_start_time = now
                self.storm.phase = self.current_storm_phase

                if self.current_storm_phase >= len(self.storm_phases):
                    self.game_phase = GamePhase.FINAL_CIRCLE

    async def _apply_storm_damage(self, dt: float):
        if not self.storm or self.game_phase not in (GamePhase.PLAYING, GamePhase.FINAL_CIRCLE):
            return

        for player in self.players.values():
            if player.state != PlayerState.ALIVE:
                continue
            if not self.storm.is_inside(player.position):
                damage = self.storm.damage_per_second * dt
                player.health -= damage

                if player.health <= 0:
                    player.health = 0
                    player.state = PlayerState.DEAD
                    self._update_alive_count()

                    kill_entry = KillFeedEntry(
                        killer_id="storm",
                        killer_name="The Storm",
                        victim_id=player.player_id,
                        victim_name=player.username,
                        weapon="storm",
                        timestamp=time.time(),
                    )
                    self.kill_feed.append(kill_entry)

                    await self.broadcast({
                        "type": "player_killed",
                        "kill_feed_entry": kill_entry.to_dict(),
                        "players_alive": self.players_alive_count,
                    })

                    await self._check_win_condition()

    def _update_projectiles(self, dt: float):
        now = time.time()
        expired = []
        for pid, proj in self.projectiles.items():
            if now - proj.timestamp > proj.ttl:
                expired.append(pid)
                continue

            proj.position.x += proj.velocity.x * dt
            proj.position.y += proj.velocity.y * dt
            proj.position.z += proj.velocity.z * dt

        for pid in expired:
            del self.projectiles[pid]

    def build_full_game_state(self) -> dict:
        """
        Build the complete game state that gets broadcast to ALL clients.
        All player positions are sent to all clients. Clients are responsible
        for filtering what to render based on distance and line of sight.
        """
        self._state_seq += 1

        all_players = {}
        for pid, player in self.players.items():
            if player.connected:
                all_players[pid] = player.to_dict(full=True)

        nearby_loot = {}
        for item_id, item in self.game_map.loot_items.items():
            if not item.picked_up:
                nearby_loot[item_id] = item.to_dict()

        state = {
            "type": "game_state",
            "seq": self._state_seq,
            "timestamp": time.time(),
            "game_phase": self.game_phase.value,
            "players": all_players,
            "players_alive": self.players_alive_count,
            "storm": self.storm.to_dict() if self.storm else None,
            "projectiles": [p.to_dict() for p in self.projectiles.values()],
            "loot_items": nearby_loot,
            "kill_feed": [kf.to_dict() for kf in self.kill_feed[-10:]],
        }

        return state

    def build_player_specific_hints(self, player_id: str, game_state: dict) -> dict:
        """
        Add player-specific rendering hints to help the client optimize.
        The client receives ALL data but uses these hints for efficient rendering.
        """
        player = self.players.get(player_id)
        if not player:
            return game_state

        hints = {
            "your_player_id": player_id,
            "render_hints": {
                "visible_players": [],
                "audible_players": [],
                "nearby_loot_ids": [],
                "in_storm": False,
                "storm_distance": 0,
            }
        }

        if self.storm:
            dx = player.position.x - self.storm.center.x
            dz = player.position.z - self.storm.center.z
            dist_to_center = math.sqrt(dx * dx + dz * dz)
            hints["render_hints"]["in_storm"] = dist_to_center > self.storm.current_radius
            hints["render_hints"]["storm_distance"] = max(
                0, dist_to_center - self.storm.current_radius
            )

        render_distance = 200.0
        audio_distance = 80.0

        for pid, other in self.players.items():
            if pid == player_id or not other.connected:
                continue
            if other.state == PlayerState.DEAD:
                continue

            dist = player.position.distance_to(other.position)

            if dist <= render_distance:
                has_los = self.game_map.check_line_of_sight(player.position, other.position)
                hints["render_hints"]["visible_players"].append({
                    "player_id": pid,
                    "distance": round(dist, 1),
                    "has_line_of_sight": has_los,
                })

            if dist <= audio_distance:
                hints["render_hints"]["audible_players"].append({
                    "player_id": pid,
                    "distance": round(dist, 1),
                })

        # Nearby loot
        loot_range = 50.0
        for item_id, item in self.game_map.loot_items.items():
            if not item.picked_up:
                dist = player.position.distance_to(item.position)
                if dist <= loot_range:
                    hints["render_hints"]["nearby_loot_ids"].append(item_id)

        # Merge hints into the game state copy
        enriched = dict(game_state)
        enriched.update(hints)
        return enriched

    async def broadcast(self, message: dict):
        if not self.connections:
            return

        data = json.dumps(message)
        disconnected = []

        for pid, ws in self.connections.items():
            try:
                await ws.send(data)
            except websockets.exceptions.ConnectionClosed:
                disconnected.append(pid)
            except Exception as e:
                logger.error(f"Error broadcasting to {pid}: {e}")
                disconnected.append(pid)

        for pid in disconnected:
            await self.remove_player(pid)

    async def broadcast_game_state(self):
        """
        Broadcast the full game state to all clients with per-player rendering hints.
        Every client gets ALL player positions for client-side prediction.
        Rendering hints help the client decide what to actually render.
        """
        if not self.connections:
            return

        base_state = self.build_full_game_state()
        disconnected = []

        for pid, ws in self.connections.items():
            try:
                # Enrich the base state with player-specific rendering hints
                player_state = self.build_player_specific_hints(pid, base_state)
                await ws.send(json.dumps(player_state))
            except websockets.exceptions.ConnectionClosed:
                disconnected.append(pid)
            except Exception as e:
                logger.error(f"Error sending state to {pid}: {e}")
                disconnected.append(pid)

        for pid in disconnected:
            await self.remove_player(pid)

    async def game_loop(self):
        self._running = True
        last_tick = time.time()
        last_broadcast = time.time()

        tick_interval = 1.0 / self.tick_rate
        broadcast_interval = 1.0 / self.broadcast_rate

        logger.info(f"Game loop started. Tick rate: {self.tick_rate}, Broadcast rate: {self.broadcast_rate}")

        while self._running:
            now = time.time()
            dt = now - last_tick
            last_tick = now

            # Phase management
            if self.game_phase == GamePhase.COUNTDOWN:
                if now >= self.game_start_time:
                    await self._start_game()

            elif self.game_phase in (GamePhase.PLAYING, GamePhase.FINAL_CIRCLE):
                # Update storm
                self._update_storm(dt)
                await self._apply_storm_damage(dt)

                # Update projectiles
                self._update_projectiles(dt)

            # Broadcast full state at broadcast_rate
            if now - last_broadcast >= broadcast_interval:
                if self.game_phase in (
                    GamePhase.PLAYING, GamePhase.FINAL_CIRCLE,
                    GamePhase.COUNTDOWN, GamePhase.DROPPING
                ):
                    await self.broadcast_game_state()
                last_broadcast = now

            # Sleep to maintain tick rate
            elapsed = time.time() - now
            sleep_time = max(0, tick_interval - elapsed)
            await asyncio.sleep(sleep_time)

    def stop(self):
        self._running = False


class BattleRoyaleServer:
    def __init__(self, host: str = "0.0.0.0", port: int = 8765):
        self.host = host
        self.port = port
        self.game = BattleRoyaleGame()
        self.player_ws_map: Dict[websockets.WebSocketServerProtocol, str] = {}

    async def handle_connection(self, websocket, path=None):
        player_id = None

        try:
            # Wait for join message
            raw = await asyncio.wait_for(websocket.recv(), timeout=10.0)
            data = json.loads(raw)

            if data.get("type") != "join":
                await websocket.send(json.dumps({
                    "type": "error",
                    "message": "First message must be join",
                }))
                return

            username = data.get("username", f"Player_{random.randint(1000, 9999)}")
            player = await self.game.add_player(websocket, username)

            if not player:
                return

            player_id = player.player_id
            self.player_ws_map[websocket] = player_id

            logger.info(f"Connection established: {username} ({player_id})")

            # Handle messages
            async for raw_message in websocket:
                try:
                    data = json.loads(raw_message)
                    await self.game.handle_player_input(player_id, data)
                except json.JSONDecodeError:
                    logger.warning(f"Invalid JSON from {player_id}")
                except Exception as e:
                    logger.error(f"Error handling message from {player_id}: {e}")

        except asyncio.TimeoutError:
            logger.warning("Connection timed out waiting for join message")
        except websockets.exceptions.ConnectionClosed:
            logger.info(f"Connection closed: {player_id}")
        except Exception as e:
            logger.error(f"Connection error: {e}")
        finally:
            if player_id:
                await self.game.remove_player(player_id)
                if websocket in self.player_ws_map:
                    del self.player_ws_map[websocket]

    async def start(self):
        logger.info(f"Starting Battle Royale Server on {self.host}:{self.port}")

        # Start game loop
        game_loop_task = asyncio.create_task(self.game.game_loop())

        # Start WebSocket server
        async with websockets.serve(
            self.handle_connection,
            self.host,
            self.port,
            ping_interval=20,
            ping_timeout=60,
            max_size=2 ** 20,  # 1MB max message
        ):
            logger.info(f"Server listening on ws://{self.host}:{self.port}")
            await asyncio.Future()  # Run forever


# Demo client for testing
class DemoClient:
    """Demo client showing how to connect and process the full game state
    with client-side distance and LOS filtering."""

    def __init__(self, uri: str, username: str):
        self.uri = uri
        self.username = username
        self.player_id = None
        self.render_distance = 150.0
        self.audio_distance = 80.0

    async def run(self):
        async with websockets.connect(self.uri) as ws:
            # Join
            await ws.send(json.dumps({
                "type": "join",
                "username": self.username,
            }))

            # Process initial response
            response = json.loads(await ws.recv())
            if response["type"] == "connected":
                self.player_id = response["player_id"]
                logger.info(f"[{self.username}] Connected as {self.player_id}")
            else:
                logger.error(f"[{self.username}] Failed to connect: {response}")
                return

            # Start sending fake movement
            move_task = asyncio.create_task(self._send_movement(ws))

            try:
                async for raw in ws:
                    data = json.loads(raw)
                    self._process_message(data)
            except websockets.exceptions.ConnectionClosed:
                logger.info(f"[{self.username}] Disconnected")
            finally:
                move_task.cancel()

    async def _send_movement(self, ws):
        x, z = random.uniform(-500, 500), random.uniform(-500, 500)
        angle = random.uniform(0, 360)

        while True:
            try:
                speed = 10.0
                dx = math.cos(math.radians(angle)) * speed * 0.05
                dz = math.sin(math.radians(angle)) * speed * 0.05
                x += dx
                z += dz

                # Random direction changes
                if random.random() < 0.05:
                    angle += random.uniform(-45, 45)

                await ws.send(json.dumps({
                    "type": "move",
                    "position": {"x": x, "y": 0, "z": z},
                    "velocity": {"x": dx / 0.05, "y": 0, "z": dz / 0.05},
                    "rotation": angle,
                    "pitch": 0,
                }))

                await asyncio.sleep(0.05)  # 20 updates per second
            except Exception:
                break

    def _process_message(self, data: dict):
        msg_type = data.get("type")

        if msg_type == "game_state":
            self._render_game_state(data)
        elif msg_type == "player_killed":
            entry = data.get("kill_feed_entry", {})
            logger.info(
                f"[{self.username}] KILL: {entry.get('killer_name')} -> "
                f"{entry.get('victim_name')} with {entry.get('weapon')}"
                f"{' (HEADSHOT!)' if entry.get('headshot') else ''}"
            )
        elif msg_type == "damage_taken":
            logger.info(
                f"[{self.username}] DAMAGE: -{data.get('damage'):.0f} "
                f"HP:{data.get('health'):.0f} Armor:{data.get('armor'):.0f}"
            )
        elif msg_type == "phase_change":
            logger.info(f"[{self.username}] Phase: {data.get('phase')}")

    def _render_game_state(self, state: dict):
        """
        Client-side filtering example.
        The server sends ALL player positions. The client decides what to render
        based on distance and line-of-sight hints from the server.
        """
        hints = state.get("render_hints", {})
        players = state.get("players", {})
        my_data = players.get(self.player_id, {})

        # Use server-provided visibility hints for rendering optimization
        visible = hints.get("visible_players", [])
        audible = hints.get("audible_players", [])

        # Players to render with full detail (in LOS and close)
        full_render = [
            v for v in visible
            if v.get("has_line_of_sight") and v.get("distance", 999) < self.render_distance
        ]

        # Players to render as indicators (audible but not visible)
        audio_indicators = [
            a for a in audible
            if a["player_id"] not in {v["player_id"] for v in full_render}
        ]

        # Players known but not rendered (out of range, behind cover)
        # Client still has their data for minimap, spectating, etc.
        all_other_ids = set(players.keys()) - {self.player_id}
        rendered_ids = {v["player_id"] for v in full_render}
        audio_ids = {a["player_id"] for a in audio_indicators}
        hidden_ids = all_other_ids - rendered_ids - audio_ids

        # Storm awareness
        in_storm = hints.get("in_storm", False)
        storm_dist = hints.get("storm_distance", 0)

        # Nearby loot to highlight in HUD
        nearby_loot = hints.get("nearby_loot_ids", [])

        # This is where a real client would pass data to the rendering engine
        # For demo, we just log periodically
        if random.random() < 0.02:  # 2% chance to log each state update
            logger.info(
                f"[{self.username}] State #{state.get('seq')} | "
                f"HP:{my_data.get('health', 0):.0f} | "
                f"Render:{len(full_render)} Audio:{len(audio_indicators)} "
                f"Hidden:{len(hidden_ids)} | "
                f"Loot nearby:{len(nearby_loot)} | "
                f"Storm:{'IN' if in_storm else 'safe'}"
                f"{'('+str(round(storm_dist))+'m)' if in_storm else ''} | "
                f"Alive:{state.get('players_alive', '?')}"
            )


async def run_demo():
    """Run the server with a few demo clients for testing."""
    server = BattleRoyaleServer(host="localhost", port=8765)

    # Start server in background
    server_task = asyncio.create_task(server.start())

    # Wait for server to start
    await asyncio.sleep(1)

    # Launch demo clients
    clients = []
    usernames = ["Shroud", "Ninja", "Tfue", "DrDisrespect", "Summit1g"]

    for name in usernames:
        client = DemoClient("ws://localhost:8765", name)
        clients.append(asyncio.create_task(client.run()))
        await asyncio.sleep(0.5)  # Stagger connections

    logger.info(f"Demo running with {len(usernames)} clients")

    # Let it run
    try:
        await asyncio.gather(*clients, return_exceptions=True)
    except KeyboardInterrupt:
        logger.info("Shutting down...")
        server.game.stop()


if __name__ == "__main__":
    try:
        asyncio.run(run_demo())
    except KeyboardInterrupt:
        logger.info("Server shut down")